import { defineConfig, mergeConfig } from "vitest/config";
import baseConfig from "./vitest.config";

export default mergeConfig(
  baseConfig,
  defineConfig({
    test: {
      include: ["src/**/*.e2e.test.ts"],
      pool: "forks",
      poolOptions: {
        forks: {
          singleFork: true,
        },
      },
    },
  }),
);

import { emailOTP } from "better-auth/plugins";
import { getTestInstance } from "better-auth/test";
import { beforeAll, describe, expect, it } from "vitest";

const baseUrl = "http://localhost:3000";
const email = "auth-e2e@example.com";
let latestOtp = "";

describe("Better Auth email OTP flow", () => {
  let auth: Awaited<ReturnType<typeof getTestInstance>>["auth"];

  beforeAll(async () => {
    const instance = await getTestInstance(
      {
        baseURL: baseUrl,
        plugins: [
          emailOTP({
            otpLength: 6,
            expiresIn: 300,
            allowedAttempts: 3,
            storeOTP: "hashed",
            async sendVerificationOTP({ otp }) {
              latestOtp = otp;
            },
          }),
        ],
      },
      { disableTestUser: true },
    );
    auth = instance.auth;
  });

  it("creates a session, reads it from its cookie, and revokes it", async () => {
    const sendResponse = await auth.handler(
      jsonRequest("/api/auth/email-otp/send-verification-otp", {
        email,
        type: "sign-in",
      }),
    );
    expect(sendResponse.status).toBe(200);
    expect(latestOtp).toMatch(/^\d{6}$/);

    const signInResponse = await auth.handler(
      jsonRequest("/api/auth/sign-in/email-otp", {
        email,
        otp: latestOtp,
        name: "Auth E2E",
      }),
    );
    expect(signInResponse.status).toBe(200);

    const cookie = signInResponse.headers.get("set-cookie");
    expect(cookie).toContain("better-auth.session_token=");
    expect(cookie).toContain("HttpOnly");
    expect(cookie).toContain("SameSite=Lax");

    const sessionResponse = await auth.handler(
      new Request(`${baseUrl}/api/auth/get-session`, {
        headers: { cookie: cookie ?? "" },
      }),
    );
    expect(sessionResponse.status).toBe(200);
    await expect(sessionResponse.json()).resolves.toMatchObject({
      user: { email },
    });

    const signOutResponse = await auth.handler(
      jsonRequest("/api/auth/sign-out", undefined, cookie ?? ""),
    );
    expect(signOutResponse.status).toBe(200);

    const clearedCookie = signOutResponse.headers.get("set-cookie");
    const signedOutSession = await auth.handler(
      new Request(`${baseUrl}/api/auth/get-session`, {
        headers: { cookie: clearedCookie ?? "" },
      }),
    );
    await expect(signedOutSession.json()).resolves.toBeNull();
  });

  it("rejects browser requests from an untrusted origin", async () => {
    const response = await auth.handler(
      new Request(`${baseUrl}/api/auth/email-otp/send-verification-otp`, {
        method: "POST",
        headers: {
          "content-type": "application/json",
          origin: "https://attacker.example",
        },
        body: JSON.stringify({ email, type: "sign-in" }),
      }),
    );

    expect(response.status).toBe(403);
  });
});

function jsonRequest(path: string, body?: unknown, cookie?: string) {
  return new Request(`${baseUrl}${path}`, {
    method: "POST",
    headers: {
      "content-type": "application/json",
      origin: baseUrl,
      ...(cookie ? { cookie } : {}),
    },
    body: body === undefined ? undefined : JSON.stringify(body),
  });
}

import { describe, expect, it, vi } from "vitest";

vi.mock("better-auth", () => ({
  betterAuth: vi.fn((options) => ({ options, api: {} })),
}));

vi.mock("better-auth/adapters/prisma", () => ({
  prismaAdapter: vi.fn(() => ({ id: "prisma-adapter" })),
}));

vi.mock("better-auth/plugins", () => ({
  customSession: vi.fn(() => ({ id: "custom-session" })),
  emailOTP: vi.fn((options) => ({ id: "email-otp", options })),
}));

vi.mock("~/server/db", () => ({
  db: {},
}));

vi.mock("~/server/mailer", () => ({
  sendSignInOtpEmail: vi.fn(),
}));

vi.mock("~/server/redis", () => ({
  getRedis: vi.fn(),
  redisKey: vi.fn((key: string) => key),
}));

vi.mock("~/env", () => ({
  env: {
    ADMIN_EMAIL: "admin@example.com",
    AUTH_EMAIL_RATE_LIMIT: 5,
    BETTER_AUTH_SECRET: "a-secure-test-secret-that-is-long-enough",
    BETTER_AUTH_URL: "http://localhost:3000",
    FROM_EMAIL: "hello@example.com",
    GITHUB_ID: "github-client-id",
    GITHUB_SECRET: "github-client-secret",
    NEXT_PUBLIC_IS_CLOUD: true,
    NODE_ENV: "test",
  },
}));

import { authConfig, authProviders } from "~/server/auth";

describe("Better Auth configuration", () => {
  it("configures GitHub with the required scopes", () => {
    expect(authConfig.socialProviders.github).toMatchObject({
      clientId: "github-client-id",
      clientSecret: "github-client-secret",
      scope: ["read:user", "user:email"],
    });
    expect(authProviders).toContainEqual({
      id: "github",
      name: "GitHub",
      type: "oauth",
    });
  });

  it("keeps numeric domain user IDs and maps legacy auth columns", () => {
    expect(authConfig.advanced.database.generateId({ model: "user" })).toBe(
      false,
    );
    expect(authConfig.session.fields).toEqual({
      token: "sessionToken",
      expiresAt: "expires",
    });
    expect(authConfig.account.fields).toMatchObject({
      accountId: "providerAccountId",
      providerId: "provider",
    });
  });

  it("enables the security controls used by the POC", () => {
    expect(authConfig.account.encryptOAuthTokens).toBe(true);
    expect(authConfig.rateLimit.enabled).toBe(true);
    expect(authConfig.rateLimit.customStorage).toBeDefined();

    const emailPlugin = authConfig.plugins.find(
      (plugin) => plugin.id === "email-otp",
    ) as { options: Record<string, unknown> };
    expect(emailPlugin.options).toMatchObject({
      allowedAttempts: 3,
      expiresIn: 300,
      otpLength: 6,
      storeOTP: "hashed",
    });
  });
});

