export default function LoginPage({
  providers,
  isSignup = false,
}: {
  providers?: AuthProvider[];
  isSignup?: boolean;
}) {
  const [emailStatus, setEmailStatus] = useState<
    "idle" | "sending" | "success"
  >("idle");

  const emailForm = useForm<z.infer<typeof emailSchema>>({
    resolver: zodResolver(emailSchema),
  });

  const otpForm = useForm<z.infer<typeof otpSchema>>({
    resolver: zodResolver(otpSchema),
  });

  async function onEmailSubmit(values: z.infer<typeof emailSchema>) {
    setEmailStatus("sending");
    const { error } = await authClient.emailOtp.sendVerificationOtp({
      email: values.email.toLowerCase(),
      type: "sign-in",
    });

    if (error) {
      setEmailStatus("idle");
      toast.error(error.message ?? "Unable to send a sign-in code");
      return;
    }

    setEmailStatus("success");
  }

  async function onOTPSubmit(values: z.infer<typeof otpSchema>) {
    const email = emailForm.getValues().email;
    const callbackUrl = inviteId
      ? `/join-team?inviteId=${inviteId}`
      : "/dashboard";
    const { error } = await authClient.signIn.emailOtp({
      email: email.toLowerCase(),
      otp: values.otp,
    });

    if (error) {
      otpForm.setError("otp", {
        message: error.message ?? "Invalid or expired code",
      });
      return;
    }

    window.location.assign(callbackUrl);
  }

  const emailProvider = providers?.find(
    (provider) => provider.type === "email",
  );

  const [submittedProvider, setSubmittedProvider] = useState<string | null>(
    null,
  );

  const searchParams = useNextSearchParams();
  const inviteId = searchParams.get("inviteId");

  const handleSubmit = async (provider: "github" | "google") => {
    setSubmittedProvider(provider);
    const callbackUrl = inviteId
      ? `/join-team?inviteId=${inviteId}`
      : "/dashboard";
    const { error } = await authClient.signIn.social({
      provider,
      callbackURL: callbackUrl,
    });
    if (error) {
      setSubmittedProvider(null);
      toast.error(error.message ?? `Unable to sign in with ${provider}`);
    }
  };

  const { resolvedTheme } = useTheme();

  return (
    <main className="h-screen flex justify-center items-center">
      <div className="flex flex-col gap-6">
        <Image
          src={"/logo-squircle.png"}
          alt="useSend"
          width={50}
          height={50}
          className="mx-auto"
        />
        <div>
          <p className="text-2xl text-center font-semibold">
            {isSignup ? "Create new account" : "Sign into useSend"}
          </p>
          <p className="text-center mt-2 text-sm text-muted-foreground">
            {isSignup ? "Already have an account?" : "New to useSend?"}
            <Link
              href={isSignup ? "/login" : "/signup"}
              className=" text-foreground hover:underline ml-1"
            >
              {isSignup ? "Sign in" : "Create new account"}
            </Link>
          </p>
        </div>

        <div className="flex flex-col gap-8 mt-8 border p-8 rounded-lg shadow">
          {providers &&
            Object.values(providers).map((provider) => {
              if (provider.type === "email") return null;
              return (
                <Button
                  key={provider.id}
                  className="w-[350px]"
                  size="lg"
                  onClick={() =>
                    handleSubmit(provider.id as "github" | "google")
                  }
                >
                  {submittedProvider === provider.id ? (
                    <Spinner className="w-5 h-5" />
                  ) : (
                    providerSvgs[provider.id as keyof typeof providerSvgs]
                  )}
                  <span className="ml-4">
                    {isSignup ? "Sign up with" : "Continue with"}{" "}
                    {provider.name}
                  </span>
                </Button>
              );
            })}
          {emailProvider && (
            <>
              <div className=" flex w-[350px]  items-center justify-between gap-2">
                <p className=" z-10 ml-[175px] -translate-x-1/2 bg-background px-4 text-sm">
                  or
                </p>
                <div className="absolute h-[1px] w-[350px]  bg-gradient-to-l from-zinc-300 via-zinc-800 to-zinc-300"></div>
              </div>
              {emailStatus === "success" ? (
                <>
                  <p className=" w-[350px] text-center text-sm">
                    We have sent an email with the OTP. Please check your inbox
                  </p>
                  <Form {...otpForm}>
                    <form
                      onSubmit={otpForm.handleSubmit(onOTPSubmit)}
                      className=""
                    >
                      <FormField
                        control={otpForm.control}
                        name="otp"
                        render={({ field }) => (
                          <FormItem>
                            <FormControl>
                              <InputOTP
                                className="w-[350px]"
                                maxLength={6}
                                pattern={REGEXP_ONLY_DIGITS_AND_CHARS}
                                inputMode="text"
                                {...field}
                              >
                                <InputOTPGroup>
                                  <InputOTPSlot
                                    className="h-12 w-[58px] text-base"
                                    index={0}
                                  />
                                  <InputOTPSlot
                                    className="h-12 w-[58px] text-base"
                                    index={1}
                                  />
                                  <InputOTPSlot
                                    className="h-12 w-[58px] text-base"
                                    index={2}
                                  />
                                  <InputOTPSlot
                                    className="h-12 w-[58px] text-base"
                                    index={3}
                                  />
                                  <InputOTPSlot
                                    className="h-12 w-[58px] text-base"
                                    index={4}
                                  />
                                  <InputOTPSlot
                                    className="h-12 w-[58px] text-base"
                                    index={5}
                                  />
                                </InputOTPGroup>
                              </InputOTP>
